import pandas as pd
import matplotlib.pyplot as plt
from mpl_toolkits.mplot3d import Axes3D
import numpy as np
import os

# Load data generated by c++ file
script_dir = os.path.dirname(os.path.abspath(__file__))
csv_path = os.path.join(script_dir, 'ackley_data.csv')
data = pd.read_csv(csv_path)

x = data['x'].unique()
y = data['y'].unique()
X, Y = np.meshgrid(x,y)
Z = data['z'].values.reshape(len(y), len(x))

fig = plt.figure(figsize=(12, 8))
ax = fig.add_subplot(111, projection='3d')

# Render the surface
surf = ax.plot_surface(X, Y, Z, cmap='terrain', edgecolor='none', alpha=0.8)

ax.set_title('Benchmark Function #2: Ackley Function')
ax.set_xlabel('X')
ax.set_ylabel('Y')
ax.set_zlabel('f(x, y)')
fig.colorbar(surf, shrink=0.5, aspect=5)

# Adjust the view to see the central global minimum hole
ax.view_init(elev=30, azim=45)

plt.show()